mapper.insert:
INSERT INTO chef (
    name, phone, skill, price, password, total_earnings, paid_amount, remaining_amount, create_time
) VALUES (
             #{name}, #{phone}, #{skill}, #{price}, #{password}, #{totalEarnings}, #{paidAmount}, #{remainingAmount}, #{createTime}
         )

mapper.update:
UPDATE chef
SET status = #{map.status}
WHERE id = #{map.chefId}

UPDATE chef
SET total_earnings = #{map.totalEarnings},
    paid_amount = #{map.paidAmount},
    remaining_amount = #{map.remainingAmount}
WHERE id = #{map.chefId}

UPDATE chef
SET total_earnings = total_earnings + #{map.amount},
    remaining_amount = remaining_amount + #{map.amount}
WHERE id = #{map.chefId}

UPDATE chef
SET paid_amount = paid_amount + #{map.amount},
    remaining_amount = remaining_amount - #{map.amount}
WHERE id = #{map.chefId}
AND remaining_amount >= #{map.amount}
